import{_ as a,o,c as n,ai as r}from"./chunks/framework.BH_J6TYN.js";const m=JSON.parse('{"title":"Solución de problemas","description":"Soluciones a los problemas más comunes","frontmatter":{"title":"Solución de problemas","description":"Soluciones a los problemas más comunes"},"headers":[],"relativePath":"shared/troubleshooting.md","filePath":"shared/troubleshooting.md"}'),i={name:"shared/troubleshooting.md"};function t(l,e,s,c,u,d){return o(),n("div",null,[...e[0]||(e[0]=[r('<h2 id="no-puedo-entrar-al-panel-de-administracion" tabindex="-1">No puedo entrar al panel de administración <a class="header-anchor" href="#no-puedo-entrar-al-panel-de-administracion" aria-label="Permalink to &quot;No puedo entrar al panel de administración&quot;">​</a></h2><p><strong>Problema:</strong> Presiono Alt+S o mantengo presionado el logo y no pasa nada.</p><p><strong>Solución:</strong></p><ol><li>En desktop: asegúrate de presionar <strong>Alt + S</strong> al mismo tiempo</li><li>En celular: mantén presionado el <strong>logo de tu negocio</strong> por 3 segundos completos, sin mover el dedo</li><li>Chequea que estés en tu página (<code>tunegocio.syntiweb.com</code>), no en otra</li><li>Si sigue sin funcionar, recarga la página y vuelve a intentar</li></ol><hr><h2 id="olvide-mi-pin" tabindex="-1">Olvidé mi PIN <a class="header-anchor" href="#olvide-mi-pin" aria-label="Permalink to &quot;Olvidé mi PIN&quot;">​</a></h2><p>Escríbenos por WhatsApp de soporte indicando el nombre de tu negocio y el correo con que te registraste. Te ayudamos a recuperarlo en minutos.</p><hr><h2 id="mi-imagen-no-sube" tabindex="-1">Mi imagen no sube <a class="header-anchor" href="#mi-imagen-no-sube" aria-label="Permalink to &quot;Mi imagen no sube&quot;">​</a></h2><p><strong>Causas comunes:</strong></p><ul><li>La imagen pesa más de 2MB → comprímela en <a href="https://squoosh.app" target="_blank" rel="noreferrer">squoosh.app</a> antes de subir</li><li>El formato no es compatible → convierte a JPG o PNG</li><li>Conexión lenta → intenta con WiFi</li><li>Alcanzaste el límite de imágenes de tu plan</li></ul><hr><h2 id="mi-pagina-no-se-ve-bien-en-el-celular" tabindex="-1">Mi página no se ve bien en el celular <a class="header-anchor" href="#mi-pagina-no-se-ve-bien-en-el-celular" aria-label="Permalink to &quot;Mi página no se ve bien en el celular&quot;">​</a></h2><ol><li>Abre tu página en el celular</li><li>Toca los tres puntos del navegador</li><li>Elige <strong>Recargar</strong> o <strong>Actualizar</strong></li></ol><p>Si sigue con problemas, escríbenos con una captura de pantalla por WhatsApp.</p><hr><h2 id="el-precio-en-bolivares-esta-desactualizado" tabindex="-1">El precio en bolívares está desactualizado <a class="header-anchor" href="#el-precio-en-bolivares-esta-desactualizado" aria-label="Permalink to &quot;El precio en bolívares está desactualizado&quot;">​</a></h2><p>La tasa BCV se actualiza automáticamente cada día. Si ves un precio desactualizado:</p><ol><li>Entra a tu panel → <strong>Configuración</strong></li><li>Dale clic al botón <strong>&quot;Actualizar&quot;</strong> junto a las tasas</li><li>Los precios se recalculan al instante</li></ol><hr><h2 id="mi-whatsapp-no-abre-cuando-el-cliente-toca-el-boton" tabindex="-1">Mi WhatsApp no abre cuando el cliente toca el botón <a class="header-anchor" href="#mi-whatsapp-no-abre-cuando-el-cliente-toca-el-boton" aria-label="Permalink to &quot;Mi WhatsApp no abre cuando el cliente toca el botón&quot;">​</a></h2><p>Chequea que el número de WhatsApp en tu configuración tenga el formato correcto: <code>584121234567</code> (código de país 58 + código de área + número, sin espacios ni guiones).</p><hr><h2 id="¿no-encuentras-tu-problema-aqui" tabindex="-1">¿No encuentras tu problema aquí? <a class="header-anchor" href="#¿no-encuentras-tu-problema-aqui" aria-label="Permalink to &quot;¿No encuentras tu problema aquí?&quot;">​</a></h2><p>Escríbenos directamente por WhatsApp de soporte. Respondemos en horario de atención de lunes a sábado.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/shared/faq.html">Preguntas frecuentes</a> — Dudas comunes sobre la plataforma</li><li><a href="/shared/whatsapp.html">Configurar WhatsApp</a> — Formato correcto del número</li><li><a href="/shared/imagenes.html">Subir imágenes</a> — Formatos y tamaños aceptados</li></ul>',27)])])}const h=a(i,[["render",t]]);export{m as __pageData,h as default};
